update modules set focus_items = '[{"prompt": "Describe your business concept.", "guidance": "Explain it the way you''d tell a stranger on a train in under thirty seconds. If you need jargon or a slide deck to make sense, the idea isn''t clear yet \u2014 simplify until it isn''t.", "placeholder": "In one or two sentences, this business is..."}, {"prompt": "Define your products or services.", "guidance": "List what you''re actually selling, not just the category. \"Coffee\" is a category. \"Single-origin pour-over coffee and pastries, sold from a walk-up counter\" is a product.", "placeholder": "What you''ll actually sell: ..."}, {"prompt": "Explain the value you provide.", "guidance": "Value isn''t a feature list \u2014 it''s the outcome someone gets. Finish this sentence: because of us, customers can now...", "placeholder": "Because of us, customers can now..."}, {"prompt": "Identify what makes your idea unique.", "guidance": "You don''t need to be first, just different in a way that matters to your customer. What would competitors have to change about themselves to copy you?", "placeholder": "What''s different about us is..."}]'::jsonb where title = 'Business Idea';

update modules set focus_items = '[{"prompt": "Understand your industry.", "guidance": "Get a feel for the size and shape of the space you''re entering \u2014 is it growing, shrinking, crowded, or wide open? You don''t need a research firm; industry reports and a few honest conversations go a long way.", "placeholder": "This industry is..."}, {"prompt": "Analyse competitors.", "guidance": "List 3-5 real alternatives customers currently use \u2014 including \"doing nothing.\" For each, note what they do well and where they leave customers wanting more.", "placeholder": "Our main competitors are... and they fall short on..."}, {"prompt": "Identify market trends.", "guidance": "What''s shifting in how people buy, live, or work that makes this a good \u2014 or risky \u2014 time to launch this business?", "placeholder": "The trend working in our favour is..."}, {"prompt": "Validate customer demand.", "guidance": "Have you actually talked to anyone who has this problem? A handful of real conversations beats a hundred assumptions.", "placeholder": "When I talked to potential customers, they said..."}]'::jsonb where title = 'Market Research';

update modules set focus_items = '[{"prompt": "Define your ideal customer.", "guidance": "Be specific enough that you could picture this person walking in the door. Age range, situation, what they care about \u2014 not \"everyone,\" which really means no one.", "placeholder": "My ideal customer is..."}, {"prompt": "Understand customer needs.", "guidance": "Separate what they say they want from what they actually need. People often ask for a faster horse when what they need is a car.", "placeholder": "What they really need is..."}, {"prompt": "Build customer personas.", "guidance": "Give your main customer type a name and a day in their life. It makes every future decision easier to test against a real person.", "placeholder": "Meet [name] \u2014 they are..."}, {"prompt": "Identify buying behaviours.", "guidance": "How do these people currently make this kind of purchase? Impulse or considered? Alone or with input from others? Price-led or trust-led?", "placeholder": "They typically decide to buy by..."}]'::jsonb where title = 'Target Customer';

update modules set focus_items = '[{"prompt": "Explain how your business generates revenue.", "guidance": "In one line: who pays you, for what, and how often? One-time purchase, subscription, commission \u2014 the mechanism matters as much as the price.", "placeholder": "We make money when..."}, {"prompt": "Identify key income streams.", "guidance": "Most businesses end up with more than one revenue stream over time. What''s your primary one now, and what could realistically be added later?", "placeholder": "Our main revenue stream is... a future stream could be..."}, {"prompt": "Understand pricing strategies.", "guidance": "Are you competing on price, or on value? Cheapest rarely wins long-term for a small business \u2014 know why someone would pay you specifically.", "placeholder": "We''re pricing based on..."}, {"prompt": "Create a sustainable model.", "guidance": "Sustainable means the money coming in reliably covers the money going out, with room to breathe. What has to be true for this to work at a small scale?", "placeholder": "For this to sustain itself, we need..."}]'::jsonb where title = 'Business Model';

update modules set focus_items = '[{"prompt": "Define your brand identity.", "guidance": "This is what people should feel, not just see. Beyond a logo \u2014 what does your business stand for that a customer could describe in their own words?", "placeholder": "We want to be known for..."}, {"prompt": "Establish your positioning.", "guidance": "Positioning is the specific space you occupy in a customer''s mind relative to alternatives. \"The affordable option\" and \"the premium option\" are both valid \u2014 pick one on purpose.", "placeholder": "Compared to alternatives, we are the..."}, {"prompt": "Develop your brand personality.", "guidance": "If your brand were a person at a party, how would they talk? Formal or casual, playful or serious? Consistency here builds trust faster than almost anything else.", "placeholder": "If our brand were a person, they''d be..."}, {"prompt": "Create a memorable customer experience.", "guidance": "Think about the one moment in dealing with you that people would actually tell a friend about. What''s that moment, and how do you make sure it happens every time?", "placeholder": "The moment we want people to remember is..."}]'::jsonb where title = 'Brand Strategy';

update modules set focus_items = '[{"prompt": "Brainstorm business names.", "guidance": "Write down more than you think you need \u2014 ten to twenty rough options. Say each one out loud; names that look fine on paper sometimes sound awkward spoken.", "placeholder": "Name options: ..."}, {"prompt": "Check availability.", "guidance": "Before you fall in love with a name, check the domain, social handles, and your local business registry. A perfect name that''s already taken is a dead end.", "placeholder": "Availability checked: ..."}, {"prompt": "Consider trademarks.", "guidance": "A quick trademark search now can save you a rebrand later. You don''t need a lawyer at this stage \u2014 just a basic search to rule out obvious conflicts.", "placeholder": "Trademark check notes: ..."}, {"prompt": "Select a name that reflects your brand.", "guidance": "The best small business names are easy to spell, easy to say, and hint at what you do or how you make people feel. Cleverness is optional; clarity isn''t.", "placeholder": "Final name and why it fits: ..."}]'::jsonb where title = 'Business Name';

update modules set focus_items = '[{"prompt": "Create a professional logo.", "guidance": "It doesn''t need to be elaborate \u2014 it needs to be legible small (like on a favicon) and work in a single colour. Simple logos age better than trendy ones.", "placeholder": "Logo direction / who''s designing it: ..."}, {"prompt": "Choose colours and typography.", "guidance": "Pick 2-3 colours and one or two fonts, then use them everywhere, consistently. Variety looks like indecision; consistency looks like a real brand.", "placeholder": "Our colours are... our fonts are..."}, {"prompt": "Define brand guidelines.", "guidance": "Write down your own rules \u2014 logo spacing, colour codes, do''s and don''ts \u2014 even a one-page version. Future-you (or anyone you hire) will thank you.", "placeholder": "Our basic guidelines: ..."}, {"prompt": "Build visual consistency.", "guidance": "Check every touchpoint a customer sees \u2014 website, packaging, social, invoices \u2014 and make sure they all look like they belong to the same business.", "placeholder": "Where we need to tighten consistency: ..."}]'::jsonb where title = 'Logo & Visual Identity';

update modules set focus_items = '[{"prompt": "Define your offerings.", "guidance": "List every product or service you''ll actually sell on day one \u2014 resist the urge to launch with everything at once. A focused offer is easier to sell and deliver well.", "placeholder": "On day one, we''re offering..."}, {"prompt": "Explain customer benefits.", "guidance": "For each offering, describe the outcome, not just the feature. Not \"noise-cancelling headphones\" but \"you can finally focus on a loud train.\"", "placeholder": "For each product, the real benefit is..."}, {"prompt": "Create product descriptions.", "guidance": "Write the actual words a customer would read when deciding to buy. If you can''t describe it compellingly in a few sentences, that''s worth knowing now.", "placeholder": "Draft description: ..."}, {"prompt": "Plan future product development.", "guidance": "What''s the natural next thing you''d add once the core offer is working? You don''t need to build it now \u2014 just know the direction.", "placeholder": "Down the line, we might add..."}]'::jsonb where title = 'Products & Services';

update modules set focus_items = '[{"prompt": "Calculate your costs.", "guidance": "Add up everything it actually costs you to deliver one unit \u2014 materials, time, fees, overhead spread across volume. Most new business owners underestimate this.", "placeholder": "It costs us roughly... to deliver one [unit]."}, {"prompt": "Set profitable prices.", "guidance": "Price needs to cover your costs and pay you for the work, not just break even. If the number feels uncomfortable to say out loud, that''s worth examining, not necessarily lowering.", "placeholder": "Our price is... because..."}, {"prompt": "Understand margin and markup.", "guidance": "Margin is profit as a percentage of the sale price; markup is profit as a percentage of cost. They''re not the same number \u2014 know both so you''re not accidentally underpricing.", "placeholder": "Our margin works out to roughly..."}, {"prompt": "Position your pricing competitively.", "guidance": "Where do you sit next to alternatives \u2014 cheaper, similar, or premium \u2014 and does that match the value you actually deliver?", "placeholder": "Relative to competitors, our pricing is..."}]'::jsonb where title = 'Pricing Strategy';

update modules set focus_items = '[{"prompt": "Build your marketing plan.", "guidance": "You don''t need every channel \u2014 you need the two or three where your actual customers already spend attention. Depth beats breadth for a small budget.", "placeholder": "Our marketing plan for the first 90 days: ..."}, {"prompt": "Choose marketing channels.", "guidance": "Where does your ideal customer already look for solutions like yours? Start there before experimenting with channels that sound exciting but don''t match your audience.", "placeholder": "Our main channels will be..."}, {"prompt": "Define your messaging.", "guidance": "One core message, said consistently, beats five clever ones said once. What''s the single sentence you want every piece of marketing to leave someone with?", "placeholder": "Our core message is..."}, {"prompt": "Create customer awareness.", "guidance": "Awareness is the step before anyone buys anything \u2014 how will a stranger first hear about you? Be specific about the actual first touchpoint.", "placeholder": "People will first hear about us through..."}]'::jsonb where title = 'Marketing Strategy';

update modules set focus_items = '[{"prompt": "Develop your sales process.", "guidance": "Map the actual steps between a stranger noticing you and handing over money. Even a simple, three-step process written down beats winging it every time.", "placeholder": "Our sales process: first they..., then..., then they buy by..."}, {"prompt": "Understand your sales funnel.", "guidance": "Not everyone who notices you will buy \u2014 and that''s normal. Roughly how many people need to see you, engage, and enquire before one becomes a customer?", "placeholder": "Rough funnel: X people see us -> Y enquire -> Z buy."}, {"prompt": "Generate leads.", "guidance": "A lead is anyone who''s shown real interest, not just anyone who''s seen your name. What''s your actual plan for getting a stranger to raise their hand?", "placeholder": "We''ll generate leads by..."}, {"prompt": "Convert enquiries into customers.", "guidance": "What happens the moment someone asks \"how much\" or \"can I book\"? A slow or unclear response loses more sales than bad pricing does.", "placeholder": "When someone enquires, we will..."}]'::jsonb where title = 'Sales Strategy';

update modules set focus_items = '[{"prompt": "Plan daily business activities.", "guidance": "Walk through an ordinary Tuesday. What has to happen, in what order, for the business to actually run? This is where good ideas meet reality.", "placeholder": "A typical day looks like..."}, {"prompt": "Identify suppliers and resources.", "guidance": "List what you depend on from outside your own control \u2014 suppliers, tools, partners, contractors. What happens if one of them lets you down?", "placeholder": "We depend on... for..."}, {"prompt": "Define business processes.", "guidance": "Write down the repeatable steps for your most common task, so it doesn''t live only in your head. This is what lets you eventually hand things off.", "placeholder": "Our process for [most common task] is..."}, {"prompt": "Improve operational efficiency.", "guidance": "Where does time or money leak right now \u2014 or where do you expect it to once you''re busier? Small fixes here compound a lot over a year.", "placeholder": "The biggest inefficiency we can see is..."}]'::jsonb where title = 'Operations Plan';

update modules set focus_items = '[{"prompt": "Estimate startup costs.", "guidance": "List everything you need to spend before you open the doors \u2014 equipment, stock, registration, a buffer for the unexpected. Round up, not down.", "placeholder": "Startup costs: ..."}, {"prompt": "Forecast revenue and expenses.", "guidance": "A rough monthly estimate for the first year beats no estimate at all. Be honest about ramp-up time \u2014 most businesses take longer than expected to reach steady sales.", "placeholder": "Rough monthly revenue... rough monthly expenses..."}, {"prompt": "Understand cash flow.", "guidance": "Profit on paper and money in the bank aren''t the same thing. When does money actually land, and when does it actually go out?", "placeholder": "Our cash flow timing looks like..."}, {"prompt": "Plan for profitability.", "guidance": "At what point \u2014 roughly how many sales, or how many months \u2014 does this business start making more than it spends? Use the break-even calculator below if it helps.", "placeholder": "We expect to become profitable around..."}]'::jsonb where title = 'Financial Planning';

update modules set focus_items = '[{"prompt": "Identify funding requirements.", "guidance": "How much do you actually need, and for what specifically? A vague number is hard to raise or budget against \u2014 tie it to your startup cost estimate.", "placeholder": "We need approximately... to cover..."}, {"prompt": "Explore finance options.", "guidance": "Savings, a small loan, friends and family, a grant, investors \u2014 each comes with different strings attached. Which fits both your needs and how much control you want to keep?", "placeholder": "Realistic funding options for us: ..."}, {"prompt": "Prepare investor information.", "guidance": "Even if you''re not raising investment yet, having a clear one-page summary of the business ready means you''re not scrambling if an opportunity comes up.", "placeholder": "Our one-line pitch: ..."}, {"prompt": "Develop a funding strategy.", "guidance": "Which option are you actually pursuing first, and what''s the backup if it falls through? Having a plan B here reduces a lot of stress later.", "placeholder": "Our funding plan: first we''ll try..., and if that doesn''t work..."}]'::jsonb where title = 'Funding';

update modules set focus_items = '[{"prompt": "Choose a business structure.", "guidance": "Sole trader, partnership, or a registered company each carry different liability and tax implications \u2014 worth a proper conversation with an accountant, not just a guess.", "placeholder": "We''re planning to structure as..."}, {"prompt": "Register your business.", "guidance": "What''s actually required in your location \u2014 a business name registration, a licence, a permit? Note the specific steps so this doesn''t quietly become a blocker later.", "placeholder": "Registration steps needed: ..."}, {"prompt": "Understand tax obligations.", "guidance": "Know roughly what you''ll owe and when, so it isn''t a shock. Setting aside a percentage of every sale from day one saves a lot of pain later.", "placeholder": "Our tax obligations include..."}, {"prompt": "Ensure legal compliance.", "guidance": "Depending on your industry, this might mean insurance, health and safety, data protection, or specific licensing. What applies to you specifically?", "placeholder": "Compliance requirements for our business: ..."}]'::jsonb where title = 'Legal & Compliance';

update modules set focus_items = '[{"prompt": "Select business software.", "guidance": "What tools will actually run the business \u2014 accounting, bookings, payments, communication? Pick boring and reliable over exciting and new at this stage.", "placeholder": "Our core tools/software: ..."}, {"prompt": "Improve productivity.", "guidance": "Where are you currently doing something manually that a tool or a simple system could take off your plate? Even small automations add up.", "placeholder": "We could save time by automating..."}, {"prompt": "Manage information effectively.", "guidance": "Where does customer, financial, and business information actually live, and can you find it in thirty seconds when you need it?", "placeholder": "Our system for keeping information organised: ..."}, {"prompt": "Build scalable systems.", "guidance": "Would this still work if you had ten times the customers? You don''t need to solve that now, but it''s worth noticing where the cracks would show first.", "placeholder": "The first thing that would break if we grew fast: ..."}]'::jsonb where title = 'Technology & Systems';

update modules set focus_items = '[{"prompt": "Identify potential risks.", "guidance": "What could realistically go wrong \u2014 a key supplier falling through, a slow season, losing your biggest customer? Naming it now takes away some of its power.", "placeholder": "The risks that worry me most are..."}, {"prompt": "Evaluate business threats.", "guidance": "Of everything you listed, which is actually likely, and which would actually hurt the most if it happened? Focus your energy on the ones that are both.", "placeholder": "The risk most likely and most damaging is..."}, {"prompt": "Develop contingency plans.", "guidance": "For your top one or two risks, what''s the actual plan if it happens? Even a rough answer beats being caught completely off guard.", "placeholder": "If [top risk] happens, our plan is..."}, {"prompt": "Strengthen business resilience.", "guidance": "What would make the business more able to absorb a bad month or a bad year \u2014 savings, diversified income, flexible costs?", "placeholder": "We can build resilience by..."}]'::jsonb where title = 'Risk Assessment';

update modules set focus_items = '[{"prompt": "Prepare for launch.", "guidance": "What genuinely has to be true before you open the doors \u2014 versus what you''re using as an excuse to delay? Separate the two honestly.", "placeholder": "Before we launch, we still need to..."}, {"prompt": "Complete your checklist.", "guidance": "List the concrete tasks between now and launch day, roughly in order. A visible checklist turns \"someday\" into an actual date.", "placeholder": "Launch checklist: ..."}, {"prompt": "Plan your first marketing campaign.", "guidance": "How will people actually find out you''ve launched? A specific plan for the first week matters more than a vague hope that word will spread.", "placeholder": "Our launch campaign: ..."}, {"prompt": "Build launch momentum.", "guidance": "What will keep attention going after the first day''s excitement fades \u2014 a follow-up offer, early reviews, referrals? Momentum has to be planned, not assumed.", "placeholder": "To keep momentum after launch day, we''ll..."}]'::jsonb where title = 'Launch Plan';

update modules set focus_items = '[{"prompt": "Define success metrics.", "guidance": "Pick a small handful of numbers that actually tell you if the business is healthy \u2014 not everything you could measure, just what matters most right now.", "placeholder": "The numbers that matter most to us are..."}, {"prompt": "Track business performance.", "guidance": "How often will you actually check these numbers, and where will you record them? A metric nobody looks at isn''t doing its job.", "placeholder": "We''ll review our numbers..."}, {"prompt": "Measure financial results.", "guidance": "Revenue, costs, and what''s left over \u2014 reviewed on a set schedule, not just when something feels off. Use the KPI board below to start tracking.", "placeholder": "Our financial review routine: ..."}, {"prompt": "Monitor continuous improvement.", "guidance": "When a number is off track, what''s your process for figuring out why and adjusting? Treat the numbers as a conversation starter, not a report card.", "placeholder": "When something''s off track, we will..."}]'::jsonb where title = 'KPI Dashboard';

update modules set focus_items = '[{"prompt": "Access templates and tools.", "guidance": "You''ve just been through the whole plan \u2014 these templates below are here so you don''t have to start from scratch for the everyday admin around running it.", "placeholder": "Templates I still need: ..."}, {"prompt": "Download useful resources.", "guidance": "Grab what''s actually relevant to where you are right now \u2014 you don''t need everything at once, just what unblocks your next step.", "placeholder": "Resources I''ll use first: ..."}, {"prompt": "Explore recommended reading.", "guidance": "Running a business is a skill you build over time. What''s one thing you want to learn more about next \u2014 pricing, marketing, hiring?", "placeholder": "I want to learn more about..."}, {"prompt": "Continue your learning journey.", "guidance": "This document isn''t really \"finished\" \u2014 it''s a living plan. What will you come back and revisit in three months, once you have real customer feedback?", "placeholder": "In three months, I''ll revisit..."}]'::jsonb where title = 'Resources';
